Here's a quick and dirty example for you:

```javascript
// Select all checkboxes
const checkboxes = document.querySelectorAll('input[type="checkbox"]');

// Function to check all checkboxes
function checkAllCheckboxes() {
    checkboxes.forEach(checkbox => checkbox.checked = true);
}

// Select the Save button and add an event listener to it
const saveButton = document.querySelector('button[type="submit"]'); // Adjust selector as needed

saveButton.addEventListener('click', function(event) {
    // Prevent the default form submission
    event.preventDefault();

    // Check all checkboxes
    checkAllCheckboxes();

    // Now you can submit the form or do whatever else you need to do
    // For example, you could manually trigger the form submission:
    const form = saveButton.closest('form');
    if (form) {
        form.submit();
    }
});
